# 2 "../FP32-Model/gap.cpp" 2

void global_avg_pool(
    const float ifmap[256][2][2],
    float ofmap[256]
) {
    GAP_C: for (int c = 0; c < 256; c++) {
        float sum = 0.0f;
        GAP_H: for (int h = 0; h < 2; h++) {
            GAP_W: for (int w = 0; w < 2; w++) {
                sum += ifmap[c][h][w];
            }
        }
        ofmap[c] = sum / (2 * 2);
    }
}
